// Build prompt segun el pais (AR/MX/ES/CO/CL)
// Perfiles inline equivalentes a src/lib/agents/countries/*.ts
const profiles = {
  AR: {
    code: 'AR', locale: 'es-AR', name: 'Argentina',
    tone: 'Apocaliptico, dramatico, sarcastico, con humor negro porteno.',
    voice: 'Voseo argentino. Cronista de policial + relator de futbol. Frases cortas y golpes de efecto.',
    idioms: ['che', 'mira vos', 'se pudrio todo', 'tremendo quilombo', 'al horno', 'no da para mas'],
    vocab: { 'autobus': 'colectivo', 'trabajo': 'laburo', 'dinero': 'guita', 'problema': 'quilombo' },
    sensitive: ['Malvinas y caidos: no se ironiza', 'Dictadura 1976-1983 y desaparecidos: nada de humor', 'AMIA y atentados: respeto a victimas'],
    rules: ['Usar voseo (tenes, sabes, mira, vos)', '1-2 modismos por nota', 'Evitar mexicanismos y espanolismos'],
    kickers: ['TREMENDO QUILOMBO', 'SE PUDRIO TODO', 'BOMBA EN CASA ROSADA', 'EXCLUSIVO', 'ESCANDALO NACIONAL']
  },
  MX: {
    code: 'MX', locale: 'es-MX', name: 'Mexico',
    tone: 'Dramatico y sensacionalista al estilo nota roja mexicana, con sarcasmo y picardia.',
    voice: 'Tuteo mexicano. Locutor de noticiero que se cree serio mientras todo se cae.',
    idioms: ['orale', 'no manches', 'esta canon', 'se armo la gorda', 'que oso', 'esta del nabo'],
    vocab: { 'amigo': 'cuate', 'trabajo': 'chamba', 'dinero': 'lana', 'fiesta': 'pachanga' },
    sensitive: ['Victimas del narco y desapariciones: no se ironiza', 'Feminicidios: jamas humor sobre victimas', 'Migrantes: no humor xenofobo'],
    rules: ['Tuteo mexicano (tu, tienes, sabes)', '1-2 mexicanismos por nota sin saturar de albur', 'Evitar argentinismos y espanolismos'],
    kickers: ['SE ARMO LA GORDA', 'NO MANCHES', 'QUE OSO', 'EXCLUSIVA', 'ESCANDALO NACIONAL']
  },
  ES: {
    code: 'ES', locale: 'es-ES', name: 'Espana',
    tone: 'Sarcastico, mordaz, ironico al estilo tertulia espanola.',
    voice: 'Tuteo peninsular con vosotros. Tertuliano cabreado que ha visto demasiado. Retranca.',
    idioms: ['tio', 'vale', 'que fuerte', 'flipo en colores', 'menudo follon', 'es la leche'],
    vocab: { 'auto': 'coche', 'computadora': 'ordenador', 'celular': 'movil', 'trabajo': 'curro' },
    sensitive: ['Victimas de ETA y 11-M: jamas humor', 'Guerra Civil y franquismo: respeto a victimas', 'Pateras y migrantes: no humor sobre ahogados'],
    rules: ['Pretérito perfecto compuesto cuando suene natural (he hecho)', 'Lexico peninsular', 'Evitar argentinismos y mexicanismos'],
    kickers: ['MENUDO FOLLON', 'ESTO ES LA REPERA', 'EXCLUSIVA', 'BOMBAZO', 'ESCANDALO NACIONAL']
  },
  CO: {
    code: 'CO', locale: 'es-CO', name: 'Colombia',
    tone: 'Dramatico y exagerado al estilo amarillista bogotano, con humor paisa y caribeno.',
    voice: 'Usted bogotano + tuteo costeno segun contexto. Locutor que se indigna y remata con chiste.',
    idioms: ['parce', 'que pena con sumerce', 'no joda', 'que chimba', 'bacano', 'una mamera'],
    vocab: { 'amigo': 'parce', 'trabajo': 'camello', 'dinero': 'plata', 'fiesta': 'rumba' },
    sensitive: ['Victimas del conflicto armado, FARC, ELN, paras: nada de humor', 'Falsos positivos: respeto a familias', 'No glorificar narcotrafico ni Pablo Escobar'],
    rules: ['Alternar tuteo y sumerce segun tono', 'Lexico colombiano (plata, parce, camello)', 'Evitar argentinismos, mexicanismos, espanolismos'],
    kickers: ['NO JODA', 'SE ARMO LA GORDA', 'EXCLUSIVA', 'BOMBAZO', 'ESCANDALO NACIONAL']
  },
  CL: {
    code: 'CL', locale: 'es-CL', name: 'Chile',
    tone: 'Sarcastico, ironico, humor seco chileno con resignacion pais.',
    voice: 'Tuteo chileno con uso frecuente de po. Locutor que lo ha visto todo y suelta perlas.',
    idioms: ['po', 'cachai', 'la raja', 'fome', 'bacan', 'al tiro', 'se armo la grande'],
    vocab: { 'amigo': 'compadre', 'trabajo': 'pega', 'dinero': 'plata', 'fiesta': 'carrete' },
    sensitive: ['Dictadura Pinochet y DDHH: no humor con detenidos desaparecidos', 'Estallido 2019 y lesiones oculares: respeto', 'Pueblo mapuche: nada racista'],
    rules: ['Tuteo chileno con po ocasional (si po, ya po)', 'Lexico chileno (pega, plata, carrete, cachai)', 'Evitar argentinismos, mexicanismos y espanolismos'],
    kickers: ['SE ARMO LA GRANDE', 'QUE LATA', 'EXCLUSIVA', 'BOMBAZO', 'ESCANDALO NACIONAL']
  }
};

function buildSystem(p) {
  const idioms = p.idioms.map(i => '- "' + i + '"').join('\n');
  const vocab = Object.entries(p.vocab).map(([k,v]) => '- ' + k + ' -> ' + v).join('\n');
  const sensitive = p.sensitive.map(s => '- ' + s).join('\n');
  const rules = p.rules.map(r => '- ' + r).join('\n');
  const kickers = p.kickers.map(k => '"' + k + '"').join(', ');
  return 'Eres el redactor satirico de RompeNoticias para ' + p.name + ' (' + p.locale + ').\n\n' +
    'TONO: ' + p.tone + '\nVOZ: ' + p.voice + '\n\n' +
    'MODISMOS (1-2 por nota):\n' + idioms + '\n\n' +
    'VOCABULARIO LOCAL:\n' + vocab + '\n\n' +
    'REGLAS:\n' + rules + '\n\n' +
    'TEMAS SENSIBLES (no se ironiza con victimas; satira al poder si):\n' + sensitive + '\n\n' +
    'KICKERS TIPICOS: ' + kickers;
}

const item = $input.first().json;
const country = (item.country || 'AR').toUpperCase();
const profile = profiles[country] || profiles.AR;

const title = item.title || '';
const description = item.contentSnippet || item.summary || item.description || '';
const link = item.link || item.guid || '';
const imageUrl = item.enclosure?.url || item['media:content']?.['$']?.url || item.image || '';

const prompt = buildSystem(profile) + '\n\n' +
  'NOTICIA ORIGINAL:\nTitulo: ' + title + '\nResumen: ' + description + '\nPais: ' + profile.code + '\nURL: ' + link + '\n\n' +
  'TAREA:\n1. Reescribe el titulo en clave satirica con tono local de ' + profile.name + '.\n' +
  '2. Redacta un excerpt de 2-3 oraciones en el mismo tono, basado en la noticia real.\n' +
  '3. Elige un kicker breve en MAYUSCULAS.\n' +
  '4. Devuelve UNICAMENTE un JSON valido (sin markdown) con este formato:\n' +
  '{\n  "title": "TITULAR SATIRICO",\n  "excerpt": "Bajada de 2-3 oraciones.",\n  "kicker": "KICKER",\n  "kicker_color": "#cc0000",\n  "size": "medium",\n  "section": "tragedias",\n  "views": "892K",\n  "country": "' + profile.code + '",\n  "locale": "' + profile.locale + '"\n}\n\n' +
  'Restricciones: kicker_color in [#cc0000, #ff6600, #e65c00]; size in [large, medium, small]; section in [tragedias, catastrofes, exclusivos, virales, escandalos].';

return [{
  json: {
    prompt,
    source_url: link,
    image_url: imageUrl,
    country: profile.code,
    locale: profile.locale,
    original_title: title
  }
}];

const response = $input.first().json;
const prev = $('Build prompt by country').first().json;

let text = '';
try { text = response.content[0].text; } catch(e) { return []; }

let parsed;
try {
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) return [];
  parsed = JSON.parse(m[0]);
} catch(e) { return []; }

const validSizes = ['large', 'medium', 'small'];
const validSections = ['tragedias', 'catastrofes', 'exclusivos', 'virales', 'escandalos'];
const validColors = ['#cc0000', '#ff6600', '#e65c00'];
const validCountries = ['AR', 'MX', 'ES', 'CO', 'CL'];

if (!parsed.title || !parsed.excerpt || !parsed.kicker) return [];

const country = validCountries.includes(parsed.country) ? parsed.country : (prev.country || 'AR');

return [{
  json: {
    title: String(parsed.title).substring(0, 300),
    excerpt: String(parsed.excerpt).substring(0, 600),
    image_url: prev.image_url || '',
    kicker: String(parsed.kicker).toUpperCase().substring(0, 50),
    kicker_color: validColors.includes(parsed.kicker_color) ? parsed.kicker_color : '#cc0000',
    size: validSizes.includes(parsed.size) ? parsed.size : 'medium',
    section: validSections.includes(parsed.section) ? parsed.section : 'tragedias',
    views: String(parsed.views || '0'),
    source_url: prev.source_url || '',
    country,
    locale: parsed.locale || prev.locale || 'es-AR',
    active: true,
    comments: 0,
    featured: false,
    sort_order: 0
  }
}];
